LOGIN_HTML = """<!DOCTYPE html>
<html lang=\"fa\" dir=\"rtl\">
<head>
<meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">
<title>ورود | OXNET</title>
<link href=\"https://cdn.jsdelivr.net/npm/@tabler/icons-webfont@latest/tabler-icons.min.css\" rel=\"stylesheet\">
<style>
@import url('https://fonts.googleapis.com/css2?family=Vazirmatn:wght@400;500;700;800;900&display=swap');
:root{--bg:#fbfaf7;--ink:#24231f;--muted:#7b776e;--line:#e8e2d8;--card:#fff;--warm:#b7791f;--warm2:#f4d29a;--green:#228862;--red:#d14b3f;--shadow:0 24px 80px rgba(50,39,20,.12)}
*{box-sizing:border-box} body{margin:0;min-height:100vh;font-family:Vazirmatn,system-ui;background:radial-gradient(circle at 10% 10%,#fff3d6,transparent 28%),linear-gradient(135deg,#fff,#f8f1e8);color:var(--ink);display:grid;place-items:center;padding:24px}.shell{width:min(100%,1020px);display:grid;grid-template-columns:1.05fr .95fr;gap:24px;align-items:stretch}.hero,.box{background:rgba(255,255,255,.82);backdrop-filter:blur(18px);border:1px solid rgba(232,226,216,.8);border-radius:34px;box-shadow:var(--shadow);overflow:hidden}.hero{padding:46px;position:relative;min-height:560px}.brand{display:flex;align-items:center;gap:14px}.mark{width:56px;height:56px;border-radius:18px;background:linear-gradient(135deg,#ffe6b5,#c98b2e);display:grid;place-items:center;font-weight:900;color:#4a2b08;font-size:22px}.brand h1{margin:0;font-size:30px;letter-spacing:-1px}.brand span{display:block;color:var(--muted);font-size:13px;margin-top:4px}.hero h2{font-size:54px;line-height:1.05;margin:70px 0 18px;letter-spacing:-2.2px}.hero p{font-size:17px;line-height:2;color:var(--muted);max-width:560px}.chips{display:flex;gap:10px;flex-wrap:wrap;margin-top:32px}.chip{padding:10px 14px;border:1px solid var(--line);border-radius:999px;background:#fffaf1;font-weight:800;font-size:13px}.orb{position:absolute;left:-90px;bottom:-90px;width:260px;height:260px;border-radius:50%;background:linear-gradient(135deg,#fff1cc,#f3b756);opacity:.7}.box{padding:34px;align-self:center}.box h3{font-size:25px;margin:0 0 7px}.sub{color:var(--muted);margin-bottom:28px}.field{display:grid;gap:8px;margin:18px 0}.field label{font-size:13px;font-weight:800;color:#5f594f}.field input{height:54px;border:1px solid var(--line);border-radius:17px;background:#fffdf9;padding:0 16px;font:inherit;outline:none;transition:.18s}.field input:focus{border-color:#cf9442;box-shadow:0 0 0 4px rgba(207,148,66,.14)}.btn{height:54px;width:100%;border:0;border-radius:17px;background:#2b2823;color:#fff;font:inherit;font-weight:900;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:10px;margin-top:18px}.err{display:none;margin-top:16px;padding:12px 14px;border-radius:14px;background:#fff0ed;color:var(--red);font-size:13px}.foot{margin-top:22px;color:var(--muted);font-size:12px;text-align:center}@media(max-width:850px){.shell{grid-template-columns:1fr}.hero{min-height:auto}.hero h2{font-size:38px;margin-top:42px}}
</style></head>
<body><main class=\"shell\"><section class=\"hero\"><div class=\"brand\"><div class=\"mark\">OX</div><div><h1>OXNET</h1><span>Version 1.1 Beta · Light control plane</span></div></div><h2>پنل روشن، سریع و قابل کنترل</h2><p>فقط خروجی‌های پایدار VLESS WebSocket و VLESS XHTTP فعال هستند. مسیر هر کانفیگ از داخل پنل قابل تغییر است.</p><div class=\"chips\"><span class=\"chip\">VLESS / WS</span><span class=\"chip\">VLESS / XHTTP</span><span class=\"chip\">All Users Beta</span><span class=\"chip\">Custom Path</span><span class=\"chip\">Admin System</span></div><div class=\"orb\"></div></section><section class=\"box\"><h3>ورود مدیر</h3><div class=\"sub\">برای مدیریت کامل کانفیگ‌ها وارد شوید.</div><form id=\"f\"><div class=\"field\"><label>رمز عبور</label><input id=\"pw\" type=\"password\" autocomplete=\"current-password\" placeholder=\"رمز مدیریت\"></div><button class=\"btn\"><i class=\"ti ti-login-2\"></i> ورود به پنل</button><div class=\"err\" id=\"err\">رمز عبور اشتباه است.</div></form><div class=\"foot\">OXNET v1.1 Beta</div></section></main><script>document.getElementById('f').onsubmit=async(e)=>{e.preventDefault();const r=await fetch('/api/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({password:pw.value})});if(r.ok)location.href='/dashboard';else err.style.display='block'};</script></body></html>"""

DASHBOARD_HTML = """<!DOCTYPE html>
<html lang=\"fa\" dir=\"rtl\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"><title>OXNET Admin</title>
<link href=\"https://cdn.jsdelivr.net/npm/@tabler/icons-webfont@latest/tabler-icons.min.css\" rel=\"stylesheet\"><script src=\"https://cdn.jsdelivr.net/npm/qrcode@1.5.3/build/qrcode.min.js\"></script>
<style>
@import url('https://fonts.googleapis.com/css2?family=Vazirmatn:wght@400;500;700;800;900&display=swap');
:root{--bg:#fbfaf7;--panel:#fff;--soft:#f7f2ea;--soft2:#fff8ea;--ink:#27251f;--muted:#746f65;--line:#e9e1d4;--accent:#a66a18;--accent2:#f1c978;--green:#16805b;--green-bg:#eaf7ef;--red:#c9473d;--red-bg:#fff0ed;--amber:#bf7a14;--shadow:0 18px 55px rgba(55,42,20,.09)}
*{box-sizing:border-box}body{margin:0;font-family:Vazirmatn,system-ui;background:linear-gradient(180deg,#fffdfa,#f5efe6);color:var(--ink)}button,input,select,textarea{font:inherit}.app{display:grid;grid-template-columns:280px 1fr;min-height:100vh}.side{position:sticky;top:0;height:100vh;padding:22px;background:rgba(255,255,255,.78);backdrop-filter:blur(20px);border-left:1px solid var(--line)}.brand{display:flex;align-items:center;gap:12px;margin-bottom:25px}.mark{width:48px;height:48px;border-radius:17px;background:linear-gradient(135deg,#fff0c9,#c6892f);display:grid;place-items:center;font-weight:900;color:#4e2d06}.brand b{font-size:22px}.brand span{display:block;color:var(--muted);font-size:12px}.nav{display:grid;gap:8px}.nav button{border:0;background:transparent;text-align:right;padding:13px 14px;border-radius:15px;color:#5d574d;cursor:pointer;display:flex;gap:10px;align-items:center;font-weight:800}.nav button.on,.nav button:hover{background:#fff4dd;color:#4e2d06}.main{padding:26px 30px 50px}.top{display:flex;align-items:center;justify-content:space-between;gap:18px;margin-bottom:24px}.title h1{margin:0;font-size:33px;letter-spacing:-1px}.title p{margin:7px 0 0;color:var(--muted)}.actions{display:flex;gap:10px;flex-wrap:wrap}.btn{border:1px solid var(--line);background:#fff;border-radius:14px;padding:11px 15px;cursor:pointer;font-weight:900;display:inline-flex;gap:8px;align-items:center;justify-content:center;color:var(--ink)}.btn.primary{background:#2b2823;color:#fff;border-color:#2b2823}.btn.warm{background:#fff4dd;color:#724307}.btn.red{background:var(--red-bg);color:var(--red);border-color:#ffd5cd}.btn.green{background:var(--green-bg);color:var(--green);border-color:#d2ecdd}.grid{display:grid;gap:16px}.metrics{grid-template-columns:repeat(4,minmax(0,1fr))}.card{background:rgba(255,255,255,.9);border:1px solid var(--line);border-radius:24px;box-shadow:var(--shadow);padding:20px}.metric{min-height:132px}.metric .ico{width:42px;height:42px;border-radius:15px;background:#fff4dd;display:grid;place-items:center;color:#8a570f;margin-bottom:14px}.metric small{color:var(--muted);font-weight:800}.metric strong{display:block;font-size:28px;margin-top:7px}.panel-title{display:flex;align-items:center;justify-content:space-between;gap:12px;margin-bottom:15px}.panel-title h2{font-size:20px;margin:0}.form{display:grid;grid-template-columns:1.2fr .8fr .8fr .8fr;gap:12px}.field{display:grid;gap:7px}.field label{font-size:12px;font-weight:900;color:#6a6357}.field input,.field select,.field textarea{border:1px solid var(--line);border-radius:14px;background:#fffdf9;min-height:46px;padding:0 12px;outline:none}.field textarea{padding:12px;min-height:82px;resize:vertical}.span2{grid-column:span 2}.span4{grid-column:span 4}.table{overflow:auto}.row{display:grid;grid-template-columns:1.4fr .8fr .8fr .7fr .8fr 1fr;gap:10px;align-items:center;padding:14px 0;border-top:1px solid var(--line)}.row.head{color:var(--muted);font-size:12px;font-weight:900;border-top:0}.pill{display:inline-flex;align-items:center;gap:6px;width:max-content;padding:7px 10px;border-radius:999px;font-size:12px;font-weight:900;background:#f4efe6;color:#665b4c}.pill.ok{background:var(--green-bg);color:var(--green)}.pill.bad{background:var(--red-bg);color:var(--red)}.mono{font-family:ui-monospace,SFMono-Regular,Menlo,monospace;direction:ltr;text-align:left;word-break:break-all}.muted{color:var(--muted)}.section{display:none}.section.on{display:block}.linkbox{background:#fffaf2;border:1px solid var(--line);border-radius:16px;padding:12px;max-height:90px;overflow:auto;font-size:11px;margin-top:10px}.inline-actions{display:flex;gap:7px;flex-wrap:wrap}.mini{padding:8px 10px;border-radius:11px;font-size:12px}.modal{position:fixed;inset:0;background:rgba(39,37,31,.34);display:none;align-items:center;justify-content:center;padding:20px;z-index:20}.modal.open{display:flex}.modal-card{width:min(680px,100%);max-height:90vh;overflow:auto;background:#fff;border-radius:26px;padding:22px;box-shadow:0 35px 110px rgba(0,0,0,.22)}.toast{position:fixed;bottom:22px;left:22px;background:#2b2823;color:#fff;padding:12px 16px;border-radius:14px;display:none;z-index:40}.log{display:grid;gap:10px}.log div{background:#fffaf2;border:1px solid var(--line);border-radius:14px;padding:12px;color:#5f574b}.settings-grid{grid-template-columns:1fr 1fr}.note{background:#fff8e7;border:1px solid #f1dbad;border-radius:18px;padding:14px;color:#6b4a11;line-height:1.8}@media(max-width:1050px){.app{grid-template-columns:1fr}.side{position:static;height:auto}.metrics,.form,.settings-grid{grid-template-columns:1fr}.span2,.span4{grid-column:auto}.row{grid-template-columns:1fr}.main{padding:20px}.top{align-items:flex-start;flex-direction:column}}
</style></head><body><div class=\"app\"><aside class=\"side\"><div class=\"brand\"><div class=\"mark\">OX</div><div><b>OXNET</b><span>Admin v1.1 Beta</span></div></div><nav class=\"nav\"><button class=\"on\" data-sec=\"overview\"><i class=\"ti ti-layout-dashboard\"></i> نمای کلی</button><button data-sec=\"links\"><i class=\"ti ti-link\"></i> کانفیگ‌ها</button><button data-sec=\"subs\"><i class=\"ti ti-folders\"></i> گروه ساب‌ها</button><button data-sec=\"settings\"><i class=\"ti ti-settings\"></i> تنظیمات</button><button data-sec=\"logs\"><i class=\"ti ti-activity\"></i> رویدادها</button></nav></aside><main class=\"main\"><div class=\"top\"><div class=\"title\"><h1 id=\"page-title\">نمای کلی</h1><p>OXNET Beta برای همه کانفیگ‌ها · VLESS-WS و VLESS-XHTTP</p></div><div class=\"actions\"><button class=\"btn green\" onclick=\"betaAll()\"><i class=\"ti ti-flask\"></i> Beta برای همه</button><button class=\"btn warm\" onclick=\"loadAll()\"><i class=\"ti ti-refresh\"></i> بروزرسانی</button><button class=\"btn\" onclick=\"logout()\"><i class=\"ti ti-logout\"></i> خروج</button></div></div><section id=\"overview\" class=\"section on\"><div class=\"grid metrics\"><div class=\"card metric\"><div class=\"ico\"><i class=\"ti ti-plug-connected\"></i></div><small>اتصالات فعال</small><strong id=\"st-conns\">—</strong></div><div class=\"card metric\"><div class=\"ico\"><i class=\"ti ti-database\"></i></div><small>ترافیک کل</small><strong id=\"st-traffic\">—</strong></div><div class=\"card metric\"><div class=\"ico\"><i class=\"ti ti-link\"></i></div><small>کانفیگ فعال</small><strong id=\"st-links\">—</strong></div><div class=\"card metric\"><div class=\"ico\"><i class=\"ti ti-clock\"></i></div><small>آپ‌تایم</small><strong id=\"st-up\">—</strong></div></div><div class=\"grid\" style=\"grid-template-columns:1.2fr .8fr;margin-top:16px\"><div class=\"card\"><div class=\"panel-title\"><h2>اتصالات زنده</h2><span class=\"pill\" id=\"conn-count\">۰</span></div><div id=\"conn-list\" class=\"log\"></div></div><div class=\"card\"><div class=\"panel-title\"><h2>پیشنهاد سیستم</h2></div><div class=\"note\">همه کاربران در کانال Beta فعال هستند. پروتکل‌های غیرقابل اتکا حذف شدند. برای هر کاربر فقط WS یا XHTTP بسازید، مسیر اختصاصی بدهید و در صورت نیاز محدودیت حجم، زمان، سرعت و IP را فعال کنید.</div></div></div></section><section id=\"links\" class=\"section\"><div class=\"card\"><div class=\"panel-title\"><h2>ساخت کانفیگ جدید</h2><button class=\"btn primary\" onclick=\"createLink()\"><i class=\"ti ti-plus\"></i> ساخت</button></div><div class=\"form\"><div class=\"field\"><label>نام</label><input id=\"cl-label\" placeholder=\"مثلاً Ali\"></div><div class=\"field\"><label>پروتکل</label><select id=\"cl-proto\"><option value=\"vless-ws\">VLESS / WS</option><option value=\"vless-xhttp-packet-up\">VLESS / XHTTP packet-up</option><option value=\"vless-xhttp-stream-up\">VLESS / XHTTP stream-up</option><option value=\"multi-auto\">WS + XHTTP</option></select></div><div class=\"field\"><label>حجم</label><input id=\"cl-limit\" type=\"number\" value=\"0\"></div><div class=\"field\"><label>واحد</label><select id=\"cl-unit\"><option>GB</option><option>MB</option></select></div><div class=\"field\"><label>روز اعتبار</label><input id=\"cl-days\" type=\"number\" value=\"0\"></div><div class=\"field\"><label>Port</label><input id=\"cl-port\" type=\"number\" value=\"443\"></div><div class=\"field\"><label>IP Limit</label><input id=\"cl-ip\" type=\"number\" value=\"0\"></div><div class=\"field\"><label>Speed Mbit/s</label><input id=\"cl-speed\" type=\"number\" value=\"0\"></div><div class=\"field span2\"><label>مسیر دلخواه</label><input id=\"cl-path\" placeholder=\"خالی = مسیر خودکار UUID\"></div><div class=\"field span2\"><label>یادداشت</label><input id=\"cl-note\" placeholder=\"اختیاری\"></div></div></div><div class=\"card\" style=\"margin-top:16px\"><div class=\"panel-title\"><h2>لیست کانفیگ‌ها</h2><span class=\"pill\" id=\"links-count\">۰</span></div><div class=\"table\"><div class=\"row head\"><div>نام</div><div>پروتکل</div><div>مصرف</div><div>وضعیت / Beta</div><div>مسیر</div><div>عملیات</div></div><div id=\"links-body\"></div></div></div></section><section id=\"subs\" class=\"section\"><div class=\"card\"><div class=\"panel-title\"><h2>گروه ساب جدید</h2><button class=\"btn primary\" onclick=\"createSub()\"><i class=\"ti ti-plus\"></i> ساخت گروه</button></div><div class=\"form\"><div class=\"field\"><label>نام گروه</label><input id=\"sub-name\"></div><div class=\"field\"><label>رمز صفحه عمومی</label><input id=\"sub-pw\"></div><div class=\"field span2\"><label>توضیح</label><input id=\"sub-desc\"></div></div></div><div class=\"card\" style=\"margin-top:16px\"><div id=\"subs-body\" class=\"log\"></div></div></section><section id=\"settings\" class=\"section\"><div class=\"grid settings-grid\"><div class=\"card\"><h2>تغییر رمز مدیر</h2><div class=\"field\"><label>رمز فعلی</label><input id=\"oldpw\" type=\"password\"></div><div class=\"field\"><label>رمز جدید</label><input id=\"newpw\" type=\"password\"></div><button class=\"btn primary\" onclick=\"changePassword()\">ذخیره رمز</button></div><div class=\"card\"><h2>استاندارد مسیر</h2><div class=\"note\">مسیرهای جدید به شکل <span class=\"mono\">/ws/your-path</span> و <span class=\"mono\">/xhttp-oxnet/packet-up/your-path</span> ساخته می‌شوند.</div></div></div></section><section id=\"logs\" class=\"section\"><div class=\"card\"><div class=\"panel-title\"><h2>رویدادهای اخیر</h2></div><div id=\"logs-body\" class=\"log\"></div></div></section></main></div><div class=\"modal\" id=\"modal\"><div class=\"modal-card\"><div class=\"panel-title\"><h2 id=\"modal-title\">جزئیات</h2><button class=\"btn\" onclick=\"closeModal()\">بستن</button></div><div id=\"modal-body\"></div></div></div><div class=\"toast\" id=\"toast\"></div><script>
let links=[],subs=[];const $=id=>document.getElementById(id);function toast(t){$('toast').textContent=t;$('toast').style.display='block';setTimeout(()=>$('toast').style.display='none',2200)}
async function authF(u,o={}){const r=await fetch(u,o);if(r.status===401)location.href='/login';return r}function fmt(b){if(!b)return '0 B';let u=['B','KB','MB','GB','TB'],i=0;while(b>=1024&&i<u.length-1){b/=1024;i++}return b.toFixed(i?2:0)+' '+u[i]}function esc(s){return String(s??'').replace(/[&<>\"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',"'":'&#39;'}[c]))}
async function loadStats(){const r=await authF('/stats'),s=await r.json();$('st-conns').textContent=s.active_connections;$('st-traffic').textContent=s.total_traffic_mb+' MB';$('st-links').textContent=s.active_links+'/'+s.links_count;$('st-up').textContent=s.uptime}
async function loadLinks(){const r=await authF('/api/links'),d=await r.json();links=d.links||[];$('links-count').textContent=links.length;renderLinks()}
async function loadSubs(){const r=await authF('/api/subs'),d=await r.json();subs=d.subs||[];renderSubs()}
async function loadConns(){const r=await authF('/api/connections'),d=await r.json();$('conn-count').textContent=d.count||0;$('conn-list').innerHTML=(d.connections||[]).map(c=>`<div><b>${esc(c.ip)}</b> · ${esc(c.label)}<br><span class=\"muted\">${esc((c.transports||[]).join(', '))} · ${esc(c.bytes_fmt)}</span></div>`).join('')||'<div class=\"muted\">اتصال فعالی وجود ندارد.</div>'}
async function loadLogs(){const r=await authF('/api/activity'),d=await r.json();$('logs-body').innerHTML=(d.logs||[]).reverse().map(l=>`<div><b>${esc(l.kind)}</b> · ${esc(l.message)}<br><span class=\"muted\">${esc(l.time)}</span></div>`).join('')||'<div class=\"muted\">هنوز رویدادی ثبت نشده است.</div>'}
async function loadAll(){await Promise.all([loadStats(),loadLinks(),loadSubs(),loadConns(),loadLogs()])}
async function betaAll(){const r=await authF('/api/beta/all',{method:'POST'});if(r.ok){const d=await r.json();toast(`Beta برای ${d.updated} کانفیگ فعال شد`);loadAll()}else toast('خطا در فعال‌سازی Beta')}
function renderLinks(){$('links-body').innerHTML=links.map(l=>{const used=l.used_bytes||0,lim=l.limit_bytes||0;return `<div class=\"row\"><div><b>${esc(l.label)}</b><br><span class=\"muted mono\">${esc(l.uuid)}</span></div><div><span class=\"pill\">${esc(l.protocol)}</span></div><div>${fmt(used)}${lim?' / '+fmt(lim):''}</div><div><span class=\"pill ${l.active&&!l.expired?'ok':'bad'}\">${l.active&&!l.expired?'فعال':'غیرفعال'}</span> ${l.beta!==false?'<span class=\"pill ok\">Beta</span>':'<span class=\"pill\">Stable</span>'}</div><div class=\"mono\">${esc(l.path_slug||l.uuid)}</div><div class=\"inline-actions\"><button class=\"btn mini\" onclick=\"details('${l.uuid}')\">لینک</button><button class=\"btn mini warm\" onclick=\"editPath('${l.uuid}')\">مسیر</button><button class=\"btn mini\" onclick=\"toggleLink('${l.uuid}',${!l.active})\">${l.active?'خاموش':'روشن'}</button><button class=\"btn mini red\" onclick=\"delLink('${l.uuid}')\">حذف</button></div></div>`}).join('')||'<div class=\"muted\">هنوز کانفیگی وجود ندارد.</div>'}
function renderSubs(){$('subs-body').innerHTML=subs.map(s=>`<div><b>${esc(s.name)}</b> · ${s.links_count} کانفیگ<br><span class=\"mono\">${esc(s.public_url)}</span><br><span class=\"mono\">${esc(s.sub_url)}</span><div class=\"inline-actions\" style=\"margin-top:8px\"><button class=\"btn mini\" onclick=\"copy('${esc(s.sub_url)}')\">کپی ساب</button><button class=\"btn mini red\" onclick=\"delSub('${s.sub_id}')\">حذف</button></div></div>`).join('')||'<div class=\"muted\">گروهی ساخته نشده است.</div>'}
async function createLink(){const body={label:$('cl-label').value,protocol:$('cl-proto').value,limit_value:+$('cl-limit').value||0,limit_unit:$('cl-unit').value,expires_days:+$('cl-days').value||0,port:+$('cl-port').value||443,ip_limit:+$('cl-ip').value||0,speed_limit_value:+$('cl-speed').value||0,speed_limit_unit:'MBIT',path_slug:$('cl-path').value,note:$('cl-note').value};const r=await authF('/api/links',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)});if(r.ok){toast('کانفیگ ساخته شد');loadAll()}else toast('خطا در ساخت')}
async function toggleLink(id,a){await authF('/api/links/'+id,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({active:a})});loadAll()}async function delLink(id){if(confirm('حذف شود؟')){await authF('/api/links/'+id,{method:'DELETE'});loadAll()}}async function editPath(id){const l=links.find(x=>x.uuid===id);const p=prompt('مسیر جدید',l.path_slug||l.uuid);if(p!==null){const r=await authF('/api/links/'+id,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({path_slug:p})});if(r.ok){toast('مسیر ذخیره شد');loadAll()}else toast('مسیر نامعتبر یا تکراری است')}}
function details(id){const l=links.find(x=>x.uuid===id);window._modalLinks=(l.links||[l.vless_link]);$('modal-title').textContent=l.label;$('modal-body').innerHTML=`<div class=\"field\"><label>Subscription</label><div class=\"linkbox mono\">${esc(l.sub_url)}</div></div>${window._modalLinks.map((x,i)=>`<div class=\"field\"><label>Config ${i+1}</label><div class=\"linkbox mono\">${esc(x)}</div><button class=\"btn mini\" onclick=\"copy(window._modalLinks[${i}])\">کپی</button></div>`).join('')}<canvas id=\"qr\"></canvas>`;$('modal').classList.add('open');try{QRCode.toCanvas($('qr'),l.sub_url,{width:220})}catch(e){}}
function closeModal(){$('modal').classList.remove('open')}function copy(t){navigator.clipboard.writeText(t).then(()=>toast('کپی شد'))}
async function createSub(){const r=await authF('/api/subs',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name:$('sub-name').value,desc:$('sub-desc').value,password:$('sub-pw').value})});if(r.ok){toast('گروه ساخته شد');loadAll()}}
async function delSub(id){if(confirm('گروه حذف شود؟')){await authF('/api/subs/'+id,{method:'DELETE'});loadAll()}}async function changePassword(){const r=await authF('/api/change-password',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({old_password:$('oldpw').value,new_password:$('newpw').value})});toast(r.ok?'رمز تغییر کرد':'رمز فعلی اشتباه است')}
async function logout(){await fetch('/api/logout',{method:'POST'});location.href='/login'}document.querySelectorAll('.nav button').forEach(b=>b.onclick=()=>{document.querySelectorAll('.nav button').forEach(x=>x.classList.remove('on'));b.classList.add('on');document.querySelectorAll('.section').forEach(s=>s.classList.remove('on'));$(b.dataset.sec).classList.add('on');$('page-title').textContent=b.textContent.trim()});loadAll();setInterval(loadAll,15000);
</script></body></html>"""

def get_public_page_html(uuid_key: str) -> str:
    return f"""<!DOCTYPE html><html lang=\"fa\" dir=\"rtl\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"><title>OXNET Subscription</title><style>@import url('https://fonts.googleapis.com/css2?family=Vazirmatn:wght@400;700;900&display=swap');body{{margin:0;font-family:Vazirmatn,system-ui;background:#fbfaf7;color:#27251f;padding:24px}}.wrap{{max-width:860px;margin:auto}}.card{{background:#fff;border:1px solid #e9e1d4;border-radius:26px;box-shadow:0 18px 55px rgba(55,42,20,.09);padding:24px;margin-top:18px}}.brand{{display:flex;gap:12px;align-items:center}}.mark{{width:48px;height:48px;border-radius:17px;background:linear-gradient(135deg,#fff0c9,#c6892f);display:grid;place-items:center;font-weight:900}}button{{border:0;border-radius:14px;background:#2b2823;color:#fff;padding:12px 16px;font:inherit;font-weight:900;cursor:pointer}}input{{border:1px solid #e9e1d4;border-radius:14px;padding:12px;font:inherit}}.mono{{direction:ltr;text-align:left;font-family:monospace;background:#fff8ea;border:1px solid #e9e1d4;border-radius:14px;padding:12px;word-break:break-all;margin:10px 0}}</style></head><body><div class=\"wrap\"><div class=\"brand\"><div class=\"mark\">OX</div><div><h1>OXNET</h1><p>صفحه عمومی ساب</p></div></div><div class=\"card\"><h2 id=\"name\">در حال بارگذاری...</h2><p id=\"desc\"></p><div id=\"pwbox\" style=\"display:none\"><input id=\"pw\" placeholder=\"رمز گروه\"><button onclick=\"loadData()\">باز کردن</button></div><div class=\"mono\" id=\"suburl\"></div><button onclick=\"copySub()\">کپی لینک ساب</button><div id=\"links\"></div></div></div><script>const KEY='{uuid_key}';let sub='';function esc(s){{return String(s||'').replace(/[&<>]/g,c=>({{'&':'&amp;','<':'&lt;','>':'&gt;'}}[c]))}}async function loadData(){{let q=pw.value?'?pw='+encodeURIComponent(pw.value):'';let r=await fetch('/api/public/sub/'+KEY+q);let d=await r.json();if(d.locked){{pwbox.style.display='block';name.textContent='این گروه رمز دارد';return}}name.textContent=d.name;desc.textContent=d.desc||'';sub=d.sub_url+(pw.value?'?pw='+encodeURIComponent(pw.value):'');suburl.textContent=sub;links.innerHTML=(d.links||[]).map(l=>'<div class=mono>'+esc(l.vless_link)+'</div>').join('')}}function copySub(){{navigator.clipboard.writeText(sub)}}loadData()</script></body></html>"""
